#include <string>

using namespace std;

string convertToBase(long long num, int base) {
    string result;
    while (num > 0) {
        int remainder = num % base;
        char c;
        if (remainder < 10) {
            c = '0' + remainder;
        } else {
            c = 'A' + (remainder - 10);
        }
        result.insert(0, 1, c);
        num /= base;
    }
    return result;
}

string solve(long long n) {
    long long n2 = n * n;
    long long n3 = n2 * n;
    string hex_part = convertToBase(n2, 16);
    string base36_part = convertToBase(n3, 36);
    return hex_part + base36_part;
}

