def convert_to_base(num, base):
    if num == 0:
        return "0"
    digits = []
    while num > 0:
        remainder = num % base
        if remainder < 10:
            digits.insert(0, str(remainder))
        else:
            digits.insert(0, chr(ord('A') + remainder - 10))
        num = num // base
    return ''.join(digits)

def solve(n: int) -> str:
    n2 = n * n
    n3 = n2 * n
    hex_part = convert_to_base(n2, 16)
    base36_part = convert_to_base(n3, 36)
    return hex_part + base36_part
```

